import { describe, expect, it } from "vitest";
import { mergeIntervals } from "../src/merge.js";

// Deep-clone helper so we can assert the input is left untouched.
const clone = (xs) => xs.map(([s, e]) => [s, e]);

describe("mergeIntervals", () => {
  describe("empty and trivial inputs", () => {
    it("maps [] -> []", () => {
      expect(mergeIntervals([])).toEqual([]);
    });

    it("returns a single interval unchanged", () => {
      expect(mergeIntervals([[1, 4]])).toEqual([[1, 4]]);
    });

    it("preserves a degenerate point interval [n, n]", () => {
      expect(mergeIntervals([[3, 3]])).toEqual([[3, 3]]);
    });
  });

  describe("overlapping intervals are merged", () => {
    it("merges the documented example [1,4],[3,6] -> [1,6]", () => {
      expect(mergeIntervals([[1, 4], [3, 6]])).toEqual([[1, 6]]);
    });

    it("merges an interval fully contained in another", () => {
      expect(mergeIntervals([[1, 10], [3, 5]])).toEqual([[1, 10]]);
    });

    it("keeps the outer bound when a later interval ends earlier", () => {
      // [2,3] must not shrink the running end from 10 down to 3.
      expect(mergeIntervals([[1, 10], [2, 3]])).toEqual([[1, 10]]);
    });

    it("chains a run of successively overlapping intervals into one", () => {
      expect(mergeIntervals([[1, 3], [2, 5], [4, 8], [7, 9]])).toEqual([[1, 9]]);
    });

    it("merges duplicate identical intervals", () => {
      expect(mergeIntervals([[1, 4], [1, 4], [1, 4]])).toEqual([[1, 4]]);
    });

    it("merges intervals sharing a start point", () => {
      expect(mergeIntervals([[1, 3], [1, 5]])).toEqual([[1, 5]]);
      expect(mergeIntervals([[1, 5], [1, 3]])).toEqual([[1, 5]]);
    });
  });

  describe("touching intervals are merged", () => {
    it("merges the documented example [1,2],[2,3] -> [1,3]", () => {
      expect(mergeIntervals([[1, 2], [2, 3]])).toEqual([[1, 3]]);
    });

    it("merges a point interval that touches a neighbour's edge", () => {
      expect(mergeIntervals([[1, 5], [5, 5]])).toEqual([[1, 5]]);
      expect(mergeIntervals([[5, 5], [5, 8]])).toEqual([[5, 8]]);
    });
  });

  describe("disjoint intervals stay separate", () => {
    it("keeps two clearly separated intervals apart", () => {
      expect(mergeIntervals([[1, 2], [4, 6]])).toEqual([[1, 2], [4, 6]]);
    });

    it("keeps intervals separated by a single unit gap apart", () => {
      // [1,2] and [3,4] do not touch (2 < 3), so they remain distinct.
      expect(mergeIntervals([[1, 2], [3, 4]])).toEqual([[1, 2], [3, 4]]);
    });

    it("returns many disjoint intervals sorted and intact", () => {
      expect(mergeIntervals([[1, 2], [4, 5], [7, 8]])).toEqual([
        [1, 2],
        [4, 5],
        [7, 8],
      ]);
    });
  });

  describe("output is sorted by start ascending", () => {
    it("sorts a reversed disjoint input", () => {
      expect(mergeIntervals([[7, 8], [4, 5], [1, 2]])).toEqual([
        [1, 2],
        [4, 5],
        [7, 8],
      ]);
    });

    it("sorts and merges an unsorted, overlapping input", () => {
      expect(mergeIntervals([[3, 6], [1, 4], [8, 10], [9, 12]])).toEqual([
        [1, 6],
        [8, 12],
      ]);
    });

    it("handles a shuffled mix of merging and disjoint intervals", () => {
      const result = mergeIntervals([
        [15, 18],
        [1, 3],
        [8, 10],
        [2, 6],
        [16, 20],
      ]);
      expect(result).toEqual([
        [1, 6],
        [8, 10],
        [15, 20],
      ]);
    });
  });

  describe("numeric ranges", () => {
    it("supports negative and zero-crossing intervals", () => {
      expect(mergeIntervals([[-5, -1], [-3, 2], [5, 7]])).toEqual([
        [-5, 2],
        [5, 7],
      ]);
    });

    it("supports fractional bounds", () => {
      expect(mergeIntervals([[1.5, 2.5], [2.5, 3.5]])).toEqual([[1.5, 3.5]]);
      expect(mergeIntervals([[0.1, 0.2], [0.30001, 0.4]])).toEqual([
        [0.1, 0.2],
        [0.30001, 0.4],
      ]);
    });
  });

  describe("input is never mutated", () => {
    it("does not mutate the outer array (length preserved)", () => {
      const input = [[1, 4], [3, 6], [8, 10]];
      mergeIntervals(input);
      expect(input.length).toBe(3);
    });

    it("does not reorder the outer array in place", () => {
      const input = [[7, 8], [1, 2], [4, 5]];
      const snapshot = clone(input);
      mergeIntervals(input);
      expect(input).toEqual(snapshot);
    });

    it("does not mutate the individual pair arrays during merging", () => {
      const input = [[1, 10], [2, 3]];
      const snapshot = clone(input);
      mergeIntervals(input);
      expect(input).toEqual(snapshot);
    });

    it("returns arrays that are not aliases of the input pairs", () => {
      const pair = [1, 4];
      const input = [pair];
      const result = mergeIntervals(input);
      expect(result[0]).not.toBe(pair);
    });

    it("returns fresh pair arrays so callers can mutate the result safely", () => {
      const input = [[1, 4]];
      const result = mergeIntervals(input);
      result[0][1] = 999;
      expect(input).toEqual([[1, 4]]);
    });

    it("returns a new outer array, not the input array", () => {
      const input = [[1, 4]];
      expect(mergeIntervals(input)).not.toBe(input);
    });
  });

  describe("throws RangeError when start > end", () => {
    it("throws for a single inverted interval", () => {
      expect(() => mergeIntervals([[5, 1]])).toThrow(RangeError);
    });

    it("throws when an inverted interval is mixed among valid ones", () => {
      expect(() => mergeIntervals([[1, 2], [9, 4], [10, 12]])).toThrow(
        RangeError,
      );
    });

    it("does not throw for a valid degenerate interval where start === end", () => {
      expect(() => mergeIntervals([[4, 4]])).not.toThrow();
    });

    it("reports the offending interval in the error message", () => {
      expect(() => mergeIntervals([[8, 3]])).toThrow(/\[8, 3\]/);
    });

    it("rejects the input before producing any output", () => {
      // Even though the first interval is valid and mergeable, an invalid
      // interval anywhere must abort the whole call.
      let result;
      expect(() => {
        result = mergeIntervals([[1, 5], [3, 6], [20, 10]]);
      }).toThrow(RangeError);
      expect(result).toBeUndefined();
    });
  });

  describe("larger integration cases", () => {
    it("collapses a fully overlapping cascade into one interval", () => {
      const input = Array.from({ length: 50 }, (_, i) => [i, i + 2]);
      // Each [i, i+2] touches/overlaps [i+1, i+3], so all collapse to [0, 51].
      expect(mergeIntervals(input)).toEqual([[0, 51]]);
    });

    it("keeps evenly spaced non-touching intervals fully separate", () => {
      const input = Array.from({ length: 5 }, (_, i) => [i * 10, i * 10 + 3]);
      expect(mergeIntervals(input)).toEqual([
        [0, 3],
        [10, 13],
        [20, 23],
        [30, 33],
        [40, 43],
      ]);
    });
  });
});

